SELECT id, template_id AS templateId, name, description, category, template_type AS templateType, campaign_group_id AS campaignGroupId, campaign_group_name AS campaignGroupName, is_active AS isActive, is_default AS isDefault, default_data_range AS defaultDataRange, enterprise_id AS enterpriseId, sid, create_time AS createTime, last_modify_time AS lastModifyTime FROM algorithm_template WHERE id IN
#{algorithmTemplateId}
ORDER BY id ASC
